    </div>
  );
};

export default Game;

import { GameConfig, CarModel, LevelConfig } from '../types';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // 0-2: Grass, 3: Lamp, 4: Fence, 5: Finish Line Flag
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  fuelBodies: any[];
  islandBodies: any[];
  rampBodies: any[];
  obstacleBodies: any[];
  boulderBodies: any[];
  finishLineBody?: any;
  endX: number;
  endY: number;
  endGlobalIndex: number;
  nextSegmentsSinceFuel: number; 
  id: number;
}

export const createEngine = (config: GameConfig) => {
  const engine = Matter.Engine.create();
  engine.gravity.y = config.GRAVITY;

  // High iterations for rigid constraints
  engine.positionIterations = 10;
  engine.velocityIterations = 10;

  return engine;
};

export const createCar = (x: number, y: number, carConfig: CarModel, gameConfig: GameConfig) => {
  // Use car specific config if available, fallback to global config
  const CAR_WIDTH = carConfig.width || gameConfig.CAR_WIDTH;
  const CAR_HEIGHT = carConfig.height || gameConfig.CAR_HEIGHT;
  const WHEEL_SIZE = carConfig.wheelSize || gameConfig.WHEEL_SIZE;

  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: carConfig.density, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: carConfig.bodyColor },
    chamfer: { radius: 15 } 
  });

  // Calculate offsets for vertical alignment
  // Positions the wheel anchor point near the edge of the chassis
  const wheelOffsetX = -CAR_WIDTH / 2 + WHEEL_SIZE;
  const wheelOffsetY = CAR_HEIGHT / 2;

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: carConfig.friction,       
    frictionStatic: 1.5, 
    density: 0.01,  // Reduced density to minimize wheel inertia/swing     
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  // Align wheels vertically with suspension points to prevent horizontal swing at rest
  const wheelA = Matter.Bodies.circle(x + wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x - wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  // Ultra-rigid settings to prevent side-to-side (pendulum) movement
  const suspensionStiffness = 1.0; 
  const suspensionDamping = 0.6;   
  const suspensionLength = 7; // Shortened slightly for tighter control

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: -wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

/**
 * Calculates the noise/height for a specific index. 
 * Supports different logic based on map type.
 */
export const getTerrainNoise = (globalIndex: number, config: GameConfig, mapType: string = 'earth'): number => {
    const baseHeight = 70;

    // Standard Logic
    const nx = globalIndex * config.TERRAIN_NOISE_FREQ_1;
    const nzOsc = Math.sin(nx * 0.2);
    let amp = 0.1;
    if (nzOsc > 0.3) amp = 1.0;
    else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

    const nPrimary = Math.sin(nx) * config.TERRAIN_AMP_1;
    const nSecondary = Math.cos(globalIndex * config.TERRAIN_NOISE_FREQ_2) * config.TERRAIN_AMP_2;
    const nRumble = Math.sin(globalIndex * config.TERRAIN_NOISE_FREQ_3) * config.TERRAIN_AMP_3;

    const difficultyMultiplier = Math.min(2.5, 1 + (globalIndex * 0.001));

    return (nPrimary + nSecondary + nRumble) * amp * difficultyMultiplier * baseHeight;
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number,
    isNight: boolean,
    config: GameConfig,
    mapType: string = 'earth',
    startSegmentsSinceFuel: number = 0,
    levelTargetDistance: number | null = null
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE, FUEL_CAN_SIZE, LAMP_SPACING } = config;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];
  const fuelBodies: any[] = [];
  const islandBodies: any[] = [];
  const rampBodies: any[] = [];
  const obstacleBodies: any[] = [];
  const boulderBodies: any[] = [];
  let finishLineBody = null;

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;
  let lastLampX = startX;
  let coinStreak = 0;
  let segmentsSinceFuel = startSegmentsSinceFuel;

  let finishLineGenerated = false;

  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;
    segmentsSinceFuel++;

    // Check if we passed level target
    if (levelTargetDistance !== null && currentX >= (200 + levelTargetDistance) && !finishLineGenerated) {
        // Flatten terrain for finish line
        const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);
        const noiseCurrent = noisePrev; // Flat
        const dy = -(noiseCurrent - noisePrev);
        currentY = prevY + dy;

        // Add finish line object
        finishLineGenerated = true;
        finishLineBody = Matter.Bodies.rectangle(currentX, currentY - 200, 20, 400, {
            isSensor: true,
            isStatic: true,
            label: 'finishLine',
            render: { visible: false }
        });

        // Add visual decoration for finish line
        decorations.push({
            x: currentX,
            y: currentY,
            angle: 0,
            scale: 1,
            type: 5 // Finish Line Type
        });
    } else {
        const noiseCurrent = getTerrainNoise(globalIndex, config, mapType);
        const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);
        const dy = -(noiseCurrent - noisePrev); 
        currentY = prevY + dy;
    }

    pathPoints.push({ x: currentX, y: currentY });

    // --- Analysis for features ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);
    const isFlatEnough = slopeFactor > 0.85; 
    let featurePlaced = false;

    // Skip obstacles near finish line
    if (finishLineGenerated) continue;

    // --- Decorations ---
    // 1. Grass (Earth Only)
    if (mapType === 'earth') {
        const density = 0.4 * slopeFactor; 
        if (Math.random() < density) {
            const t = Math.random();
            const decoX = prevX + (currentX - prevX) * t;
            const decoY = prevY + (currentY - prevY) * t;

            decorations.push({
                x: decoX,
                y: decoY,
                angle: angle,
                scale: 0.5 + Math.random() * 0.5,
                type: Math.floor(Math.random() * 3) 
            });
        }
    }

    // 2. Lamps
    const lampChance = isNight || mapType === 'highway';
    if (lampChance && (currentX - lastLampX) > LAMP_SPACING) {
        decorations.push({
            x: currentX,
            y: currentY,
            angle: angle,
            scale: 1.0,
            type: 3
        });
        lastLampX = currentX;
    }

    // 3. Fences (Highway)
    if (mapType === 'highway') {
        decorations.push({
            x: prevX,
            y: prevY,
            angle: angle,
            scale: 1.0,
            type: 4
        });
    }

    // --- Collectibles (Fuel & Coins) ---
    const forceFuel = segmentsSinceFuel >= 125; 
    const canSpawnFuel = (segmentsSinceFuel > 80 && isFlatEnough) || forceFuel;

    let fuelSpawnedHere = false;

    if (canSpawnFuel) {
        if (forceFuel || Math.random() < 0.1) {
             const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;

            const fuel = Matter.Bodies.rectangle(cx, cy, FUEL_CAN_SIZE * 0.8, FUEL_CAN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'fuel',
                angle: 0,
                render: { visible: false }
            });
            fuelBodies.push(fuel);
            segmentsSinceFuel = 0;
            coinStreak = 0; 
            fuelSpawnedHere = true;
        }
    }

    if (!fuelSpawnedHere && !featurePlaced) {
        let placeCoin = false;
        if (coinStreak > 0) {
            if (isFlatEnough) {
                placeCoin = true;
                coinStreak--;
            } else {
                coinStreak = 0;
            }
        } else {
            if (Math.random() < 0.05 && isFlatEnough) {
                coinStreak = 3 + Math.floor(Math.random() * 6);
                placeCoin = true;
                coinStreak--;
            }
        }

        if (placeCoin) {
            const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Ground
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: config.FRICTION || 1.0, 
         frictionStatic: config.FRICTION || 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  // Combine all bodies into composite
  const allBodies = [
      ...groundParts, 
      ...coinBodies, 
      ...fuelBodies, 
      ...islandBodies, 
      ...rampBodies, 
      ...obstacleBodies,
      ...boulderBodies,
      ...(finishLineBody ? [finishLineBody] : [])
  ];

  return { 
      composite: Matter.Composite.create({ bodies: allBodies }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      fuelBodies,
      islandBodies,
      rampBodies,
      obstacleBodies,
      boulderBodies,
      finishLineBody,
      endX: currentX,
      endY: currentY,
      endGlobalIndex: globalIndex,
      nextSegmentsSinceFuel: segmentsSinceFuel, 
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig, GameMode, LevelConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  mode: GameMode;
  levelConfig?: LevelConfig;
  onGameOver: (distance: number, coins: number) => void;
  onLevelComplete: (coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: any) => void;
  onResetConfig: () => void;
  onExit: () => void;
  isMenuBackground?: boolean;
  onReady?: () => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark' | 'explosion';
}

interface StuntState {
    inAir: boolean;
    startAngle: number;
    flips: number;
    airTime: number;
}

const Game: React.FC<GameProps> = ({ mode, levelConfig, onGameOver, onLevelComplete, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig, onExit, isMenuBackground = false, onReady }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Physics State
  const wheelGroundContacts = useRef(0); 
  const stuntRef = useRef<StuntState>({ inAir: false, startAngle: 0, flips: 0, airTime: 0 });
  const processedBodyIds = useRef<Set<number>>(new Set());
  const fuelRef = useRef(config.MAX_FUEL);
  const isOutOfFuelRef = useRef(false);

  // Pause State
  const [isPaused, setIsPaused] = useState(false);
  const pausedRef = useRef(false);
  const isReadyRef = useRef(false);

  // Debug State
  const [isDebugOpen, setIsDebugOpen] = useState(false);

  // UI Notification State
  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);

  // Day/Night Cycle
  const gameTimeRef = useRef(0);
  const isNightRef = useRef(false);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0, segmentsSinceFuel: 0 });
  const loadedChunksRef = useRef<any[]>([]); 

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 });

  // Refs for direct DOM manipulation (HUD)
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const hudFuelBarRef = useRef<HTMLDivElement>(null);
  const hudFpsRef = useRef<HTMLDivElement>(null);

  // FPS Logic Refs
  const lastFpsTimeRef = useRef(0);
  const frameCountRef = useRef(0);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);

  // Images & Patterns
  const carImageRef = useRef<HTMLImageElement | null>(null);
  const patternsRef = useRef<{[key: string]: CanvasPattern | null}>({});

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data
  const [clouds, setClouds] = useState<Cloud[]>([]);
  const [stars, setStars] = useState<{x: number, y: number, r: number, opacity: number}[]>([]);
  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());
  const [collectedFuelIds, setCollectedFuelIds] = useState<Set<number>>(new Set());

  // Generate static stars for Moon
  useEffect(() => {
      if (selectedMap.backgroundType === 'moon') {
          const s = [];
          for(let i=0; i<150; i++) {
              s.push({
                  x: Math.random() * 2000,
                  y: Math.random() * 1000 - 500,
                  r: Math.random() * 2,
                  opacity: Math.random()
              });
          }
          setStars(s);
      } else {
          setStars([]);
      }
  }, [selectedMap]);

  // Load Car Image if needed
  useEffect(() => {
      if (selectedCar.imageUrl) {
          const img = new Image();
          img.src = selectedCar.imageUrl;
          img.onload = () => { carImageRef.current = img; };
      } else {
          carImageRef.current = null;
      }
  }, [selectedCar.imageUrl]);

  // Pattern Generation Helper
  const getPattern = useCallback((ctx: CanvasRenderingContext2D, type: string, color1: string, color2: string) => {
      const key = `${type}-${color1}-${color2}`;
      if (patternsRef.current[key]) return patternsRef.current[key];

      const pCanvas = document.createElement('canvas');
      const pCtx = pCanvas.getContext('2d');
      if (!pCtx) return null;

      if (type === 'ground') {
          pCanvas.width = 40; pCanvas.height = 40;
          // Rotate pattern? Hard to rotate offscreen canvas pattern easily without rotation transform on use
          // We'll draw a static texture
          pCtx.fillStyle = color1;
          pCtx.fillRect(0,0,40,40);
          pCtx.fillStyle = color2;
          pCtx.globalAlpha = 0.3;
          pCtx.beginPath();
          pCtx.arc(10, 10, 2, 0, Math.PI*2);
          pCtx.arc(30, 30, 3, 0, Math.PI*2);
          pCtx.fill();
      } else if (type === 'striped') {
          pCanvas.width = 20; pCanvas.height = 20;
          pCtx.fillStyle = color1;
          pCtx.fillRect(0,0,20,20);
          pCtx.fillStyle = color2;
          pCtx.beginPath();
          pCtx.moveTo(10,0); pCtx.lineTo(20,0); pCtx.lineTo(10,20); pCtx.lineTo(0,20);
          pCtx.fill();
      } else if (type === 'checker') {
          pCanvas.width = 20; pCanvas.height = 20;
          pCtx.fillStyle = color1;
          pCtx.fillRect(0,0,20,20);
          pCtx.fillStyle = color2;
          pCtx.fillRect(0,0,10,10);
          pCtx.fillRect(10,10,10,10);
      } else if (type === 'dots') {
          pCanvas.width = 10; pCanvas.height = 10;
          pCtx.fillStyle = color1;
          pCtx.fillRect(0,0,10,10);
          pCtx.fillStyle = color2;
          pCtx.beginPath();
          pCtx.arc(5,5,2,0,Math.PI*2);
          pCtx.fill();
      }

      const pattern = ctx.createPattern(pCanvas, 'repeat');
      patternsRef.current[key] = pattern;
      return pattern;
  }, []);

  // Initialize Physics & Game
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex, segmentsSinceFuel } = lastChunkDataRef.current;
      const length = config.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(
          chunkId, startX, endY, globalIndex, length, isNightRef.current, config, selectedMap.backgroundType, segmentsSinceFuel,
          mode === 'LEVELS' && levelConfig ? levelConfig.distance : null
      );

      if (engineRef.current) Matter.World.add(engineRef.current.world, newChunk.composite);
      loadedChunksRef.current.push(newChunk.composite);

      if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
          const newClouds = generateClouds(startX, length);
          setClouds(prev => [...prev, ...newClouds]);
      }

      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex,
          segmentsSinceFuel: newChunk.nextSegmentsSinceFuel
      };

      setChunks(prev => [...prev, newChunk]);
  }, [config, selectedMap.backgroundType, mode, levelConfig]);

  // Handle Resize
  const handleResize = useCallback(() => {
      if (canvasRef.current && containerRef.current) {
          // Set canvas internal resolution based on config
          const rw = containerRef.current.clientWidth * config.RESOLUTION;
          const rh = containerRef.current.clientHeight * config.RESOLUTION;
          canvasRef.current.width = rw;
          canvasRef.current.height = rh;

          // Clear pattern cache on resize/config change to be safe
          patternsRef.current = {};
      }
  }, [config.RESOLUTION]);

  useEffect(() => {
      window.addEventListener('resize', handleResize);
      handleResize();
      return () => window.removeEventListener('resize', handleResize);
  }, [handleResize]);

  // Init Engine
  useEffect(() => {
    if (!isMenuBackground) soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;
    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;
    const wall = createWall(-1000);
    wallRef.current = wall;
    Matter.World.add(engine.world, [car, wall]);

    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 }; 
    const bufferDist = isMenuBackground ? config.CHUNK_SIZE * 2 : (config.INITIAL_BUFFER_DISTANCE || 3000);
    let currentGenX = 0;
    while (currentGenX < bufferDist) {
        addChunk(currentGenX);
        currentGenX += config.CHUNK_SIZE;
    }

    particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
        x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
    }));

    isReadyRef.current = true;
    if (onReady) onReady();

    // Physics Events (Collisions)
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        // ... (Keep existing collision logic mostly the same, removed DOM manipulations)
        const pairs = event.pairs;
        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;
            // ... (Simple logic copies)
            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle'; 
            if ((isWheelA && isGround(bodyB)) || (isWheelB && isGround(bodyA))) wheelGroundContacts.current += 1;

            const isChassisA = bodyA.label === 'chassis';
            const isChassisB = bodyB.label === 'chassis';
            const isFatalGround = (b: any) => b.label === 'ground';

            if ((isChassisA && isFatalGround(bodyB)) || (isChassisB && isFatalGround(bodyA))) {
                if (isMenuBackground) continue;
                const chassisBody = isChassisA ? bodyA : bodyB;
                // Simplified Angle Check for Game Over
                if (Math.abs(chassisBody.angle) > Math.PI / 1.5) { // Upside down roughly
                     gameStateRef.current.isGameOver = true;
                     soundManagerRef.current?.stopContinuous();
                     onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                }
            }

            // Collectibles
            let itemBody = null;
            const isCarPart = (b: any) => ['chassis', 'wheelBack', 'wheelFront'].includes(b.label);
            if (isCarPart(bodyA) && ['coin', 'fuel', 'finishLine'].includes(bodyB.label)) itemBody = bodyB;
            if (isCarPart(bodyB) && ['coin', 'fuel', 'finishLine'].includes(bodyA.label)) itemBody = bodyA;

            if (itemBody && !isMenuBackground) {
                if (itemBody.label === 'finishLine') {
                    gameStateRef.current.isGameOver = true;
                    soundManagerRef.current?.stopContinuous();
                    onLevelComplete(gameStateRef.current.coins);
                } else if (!processedBodyIds.current.has(itemBody.id)) {
                    processedBodyIds.current.add(itemBody.id);
                    Matter.World.remove(engine.world, itemBody, true);
                    if (itemBody.label === 'coin') {
                        soundManagerRef.current?.playCoinSound();
                        gameStateRef.current.coins += config.COIN_VALUE;
                        setCollectedCoinIds(prev => { const next = new Set(prev); next.add(itemBody.id); return next; });
                    } else if (itemBody.label === 'fuel') {
                        soundManagerRef.current?.playCoinSound();
                        fuelRef.current = Math.min(config.MAX_FUEL, fuelRef.current + config.FUEL_CAN_VALUE);
                        isOutOfFuelRef.current = false;
                        setNotification({ text: "FUEL!", subText: `+${Math.round(config.FUEL_CAN_VALUE/config.MAX_FUEL * 100)}%`, id: Date.now() });
                        setTimeout(() => setNotification(null), 1500);
                        setCollectedFuelIds(prev => { const next = new Set(prev); next.add(itemBody.id); return next; });
                    }
                }
            }
            // Particles
            if ((isWheelA && isGround(bodyB)) || (isWheelB && isGround(bodyA))) {
                const b = isWheelA ? bodyA : bodyB;
                const speed = Matter.Vector.magnitude(b.velocity);
                if (speed > 5) spawnParticles(b.position.x, b.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
            }
        }
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        const pairs = event.pairs;
        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;
            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';
            if ((isWheelA && isGround(bodyB)) || (isWheelB && isGround(bodyA))) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);
    return () => {
        if (requestRef.current) cancelAnimationFrame(requestRef.current);
        Matter.Engine.clear(engine);
        if (soundManagerRef.current) soundManagerRef.current.stopContinuous();
    };
  }, [addChunk, selectedCar, onGameOver, config.CHUNK_SIZE, mode, levelConfig, isMenuBackground, onReady]);

  // Keep physics separate for clarity? No, we need direct render loop access.

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark' | 'explosion') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 20 - 10);
              p.y = y + (Math.random() * 20 - 10);
              p.type = type;
              p.maxLife = type === 'explosion' ? 60 : config.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;
              const speed = type === 'explosion' ? Math.random() * 10 + 5 : Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI * 2;
              p.vx = Math.cos(angle) * speed;
              p.vy = Math.sin(angle) * speed;
              spawned++;
          }
      }
  };

  // --- DRAWING FUNCTIONS ---

  const drawCar = (ctx: CanvasRenderingContext2D, chassis: any, wheelBack: any, wheelFront: any) => {
      // Draw Wheels First
      [wheelBack, wheelFront].forEach(w => {
          ctx.save();
          ctx.translate(w.position.x, w.position.y);
          ctx.rotate(w.angle);

          const r = selectedCar.wheelSize || config.WHEEL_SIZE;
          ctx.beginPath();
          ctx.arc(0, 0, r, 0, Math.PI * 2);
          ctx.fillStyle = '#171717';
          ctx.fill();
          ctx.lineWidth = 2;
          ctx.strokeStyle = '#000';
          ctx.stroke();

          // Rim
          ctx.beginPath();
          ctx.arc(0, 0, r * 0.7, 0, Math.PI * 2);
          ctx.fillStyle = selectedCar.wheelColor;
          ctx.fill();
          ctx.stroke();

          // Spokes
          ctx.strokeStyle = '#171717';
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.moveTo(0, -r*0.7); ctx.lineTo(0, r*0.7);
          ctx.moveTo(-r*0.6, -r*0.35); ctx.lineTo(r*0.6, r*0.35);
          ctx.moveTo(-r*0.6, r*0.35); ctx.lineTo(r*0.6, -r*0.35);
          ctx.stroke();

          ctx.restore();
      });

      // Draw Chassis
      ctx.save();
      ctx.translate(chassis.position.x, chassis.position.y);
      ctx.rotate(chassis.angle);

      if (carImageRef.current) {
          const w = config.CAR_WIDTH * (selectedCar.imageScale || 1);
          const h = config.CAR_HEIGHT * (selectedCar.imageScale || 1);
          const yOff = (selectedCar.imageYOffset || 0);
          ctx.drawImage(carImageRef.current, -w/2, -h/2 + yOff, w, h);
      } else {
          // Vector Drawing
          let fill: string | CanvasPattern = selectedCar.bodyColor;
          if (selectedCar.texture !== 'plain') {
              const p = getPattern(ctx, selectedCar.texture, selectedCar.bodyColor, selectedCar.textureColor2 || '#000');
              if (p) fill = p;
          }
          ctx.fillStyle = fill;
          ctx.strokeStyle = 'rgba(0,0,0,0.5)';
          ctx.lineWidth = 2;

          // Draw Shape based on selectedCar.shape
          ctx.beginPath();
          if (selectedCar.shape === 'coupe') {
              ctx.moveTo(-85, 15); ctx.lineTo(-85, -5); ctx.lineTo(-75, -15);
              ctx.lineTo(-50, -35); ctx.lineTo(10, -35); ctx.lineTo(40, -15);
              ctx.lineTo(75, -5); ctx.lineTo(85, 15);
          } else if (selectedCar.shape === 'jeep') {
              // Simple Jeep
              ctx.rect(-80, -15, 160, 30);
              ctx.rect(-50, -45, 70, 30);
          } else {
              // Generic box fallback for other shapes to keep code small, or add detailed paths
              ctx.rect(-config.CAR_WIDTH/2, -config.CAR_HEIGHT/2, config.CAR_WIDTH, config.CAR_HEIGHT);
          }
          ctx.closePath();
          ctx.fill();
          ctx.stroke();

          // Simple window for details
          ctx.fillStyle = '#1e293b';
          if (selectedCar.shape === 'coupe') {
              ctx.beginPath(); ctx.moveTo(-45, -32); ctx.lineTo(5, -32); ctx.lineTo(30, -15); ctx.lineTo(-65, -15); ctx.fill();
          } else if (selectedCar.shape === 'jeep') {
              ctx.fillRect(-45, -40, 30, 20);
          }
      }
      ctx.restore();
  };

  const animate = useCallback(() => {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d', { alpha: false }); // Optimize for no transparency on canvas background
      const engine = engineRef.current;
      const car = carRef.current;

      if (!canvas || !ctx || !engine || !car || gameStateRef.current.isGameOver || !isReadyRef.current) {
          requestRef.current = requestAnimationFrame(animate);
          return;
      }

      // 1. Update Physics
      if (!pausedRef.current) {
          Matter.Engine.update(engine, 1000 / 60);
          // ... (Input & Physics Logic same as before)
          const { keys } = gameStateRef.current;
          const chassis = car.bodies.find((b: any) => b.label === 'chassis');
          const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
          const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

          // Camera Update
          cameraPosRef.current = { x: chassis.position.x, y: chassis.position.y };
          const velocity = Matter.Vector.magnitude(chassis.velocity);
          const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
          const targetZoom = 1.0 + speedRatio * (config.MAX_ZOOM_FACTOR - 1.0);
          cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

          // Sound Update
          const isGrounded = wheelGroundContacts.current > 0;
          if (soundManagerRef.current && !isMenuBackground) {
              soundManagerRef.current.updateContinuous(Math.min(1.5, velocity / 25), isGrounded, keys.right && !isOutOfFuelRef.current);
          }

          // Input Handling
          const maxSpeed = selectedCar.speed * (isMenuBackground ? 0.6 : 1.0);
          const acceleration = selectedCar.acceleration;
          const maxRotation = config.MAX_ROTATION_SPEED;
          const rotationSpeed = isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED;

          if (isMenuBackground) { keys.right = true; if(chassis.angle < -0.5) Matter.Body.setAngle(chassis, -0.5); }

          const applyPower = (target: number) => {
              if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelBack, target);
              if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelFront, target);
          };

          if (keys.right && !isOutOfFuelRef.current) {
              fuelRef.current -= config.FUEL_CONSUMPTION;
              if (fuelRef.current <= 0) { fuelRef.current = 0; isOutOfFuelRef.current = true; setNotification({text:"OUT OF FUEL", id: Date.now()}); setTimeout(() => { if (!gameStateRef.current.isGameOver) { gameStateRef.current.isGameOver = true; onGameOver(gameStateRef.current.distance, gameStateRef.current.coins); } }, 2000); }
              const curSpeed = selectedCar.driveTrain === 'FWD' ? wheelFront.angularVelocity : wheelBack.angularVelocity;
              if (curSpeed < maxSpeed) applyPower(Math.min(curSpeed + acceleration, maxSpeed));
              if (chassis.angularVelocity > -maxRotation) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - rotationSpeed);
          } else if (keys.left && !isOutOfFuelRef.current) {
              const curSpeed = selectedCar.driveTrain === 'FWD' ? wheelFront.angularVelocity : wheelBack.angularVelocity;
              const targetRev = -maxSpeed * 0.5;
              if (curSpeed > targetRev) applyPower(Math.max(curSpeed - acceleration*1.5, targetRev));
              if (chassis.angularVelocity < maxRotation) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + rotationSpeed*0.5);
          }

          // HUD Update
          const dist = Math.max(0, Math.floor((chassis.position.x - 200) / 10));
          gameStateRef.current.distance = dist;
          if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${dist}`;
          if (hudCoinsRef.current) hudCoinsRef.current.innerText = `${gameStateRef.current.coins}`;
          if (hudFuelBarRef.current) hudFuelBarRef.current.style.width = `${(fuelRef.current / config.MAX_FUEL) * 100}%`;

          // Chunk Loading
          if (chassis.position.x > lastChunkDataRef.current.endX - config.RENDER_DISTANCE) addChunk(lastChunkDataRef.current.endX);

          // Particles
          particlesRef.current.forEach(p => {
              if(p.active) {
                  p.x += p.vx; p.y += p.vy; p.vy += p.type === 'explosion' ? 0.05 : 0.2; p.life--;
                  if (p.life <= 0) p.active = false;
              }
          });
      }

      // 2. RENDER (Canvas)
      const CONFIG = config;
      const zoom = cameraZoomRef.current;
      const viewW = CONFIG.BASE_VIEWPORT_WIDTH * zoom;
      const viewH = CONFIG.BASE_VIEWPORT_HEIGHT * zoom;

      const chassis = car.bodies.find((b: any) => b.label === 'chassis');
      const cx = chassis.position.x;
      const cy = chassis.position.y;

      const viewBoxX = cx - viewW * 0.3;
      const viewBoxY = cy - viewH * 0.6;

      // Transform context to Camera
      // Scale canvas to fit viewport
      const scaleX = canvas.width / viewW;
      const scaleY = canvas.height / viewH;

      ctx.setTransform(scaleX, 0, 0, scaleY, -viewBoxX * scaleX, -viewBoxY * scaleY);

      // Draw Background (Sky)
      const grad = ctx.createLinearGradient(viewBoxX, viewBoxY, viewBoxX, viewBoxY + viewH);
      // Need dynamic sky colors
      const isNight = isNightRef.current; // Simplified, ref access OK
      // For proper gradients we need the values from animate loop earlier if we did interpolation
      // But for now use map defaults or simple logic
      grad.addColorStop(0, isNight ? COLORS.skyNightStart : selectedMap.skyColorStart);
      grad.addColorStop(1, isNight ? COLORS.skyNightEnd : selectedMap.skyColorEnd);
      ctx.fillStyle = grad;
      ctx.fillRect(viewBoxX, viewBoxY, viewW, viewH);

      // Draw Stars (if moon)
      if (stars.length > 0) {
          ctx.fillStyle = 'white';
          stars.forEach(s => {
              const plx = s.x + viewBoxX * 0.9; // Parallax
              ctx.globalAlpha = s.opacity;
              ctx.beginPath(); ctx.arc(plx, s.y, s.r, 0, Math.PI*2); ctx.fill();
          });
          ctx.globalAlpha = 1;
      }

      // Draw Clouds
      ctx.fillStyle = 'rgba(255,255,255,0.6)';
      clouds.forEach(c => {
          if (c.x + 200 > viewBoxX && c.x - 200 < viewBoxX + viewW) {
              ctx.save();
              ctx.translate(c.x, c.y);
              ctx.scale(c.scale, c.scale);
              ctx.beginPath();
              ctx.arc(0,0,30,0,Math.PI*2);
              ctx.arc(40,10,40,0,Math.PI*2);
              ctx.arc(80,0,30,0,Math.PI*2);
              ctx.fill();
              ctx.restore();
          }
      });

      // Draw Terrain (Ground)
      const groundPattern = getPattern(ctx, 'ground', selectedMap.groundColor, selectedMap.groundDarkColor);
      ctx.fillStyle = groundPattern || selectedMap.groundColor;
      ctx.strokeStyle = selectedMap.groundDarkColor;
      ctx.lineWidth = 5;

      chunks.forEach(chunk => {
          // Culling
          if (chunk.endX < viewBoxX || chunk.pathData[0].x > viewBoxX + viewW) return;

          ctx.beginPath();
          const pts = chunk.pathData;
          if(pts.length > 0) {
              ctx.moveTo(pts[0].x, pts[0].y);
              for(let i=1; i<pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
              ctx.lineTo(pts[pts.length-1].x, pts[pts.length-1].y + 800);
              ctx.lineTo(pts[0].x, pts[0].y + 800);
              ctx.closePath();
              ctx.fill();
              ctx.stroke();
          }

          // Decorations
          chunk.decorations.forEach(d => {
              ctx.save();
              ctx.translate(d.x, d.y);
              ctx.rotate(d.angle);
              ctx.scale(d.scale, d.scale);

              if (d.type === 5) { // Finish
                  ctx.fillStyle = '#fff';
                  ctx.fillRect(-5, -200, 10, 200);
                  ctx.fillStyle = '#000';
                  ctx.beginPath(); ctx.moveTo(0, -200); ctx.lineTo(100, -180); ctx.lineTo(0, -160); ctx.fill();
              } else if (d.type === 3) { // Lamp
                  ctx.fillStyle = '#475569';
                  ctx.fillRect(-2, -80, 4, 80);
                  ctx.fillStyle = '#fef08a';
                  ctx.beginPath(); ctx.arc(15, -80, 5, 0, Math.PI*2); ctx.fill();
              } else if (d.type === 4) { // Fence
                  ctx.fillStyle = '#94a3b8';
                  ctx.fillRect(0, -15, 5, 15);
                  ctx.fillRect(0, -12, 40, 4);
              } else if (selectedMap.backgroundType === 'earth') { // Grass
                  ctx.strokeStyle = '#065f46';
                  ctx.lineWidth = 2;
                  ctx.beginPath(); 
                  ctx.moveTo(0,0); ctx.quadraticCurveTo(5, -15, 0, -25);
                  ctx.moveTo(-3,0); ctx.quadraticCurveTo(-8, -10, -5, -20);
                  ctx.stroke();
              }
              ctx.restore();
          });

          // Obstacles & Boulders
          if (chunk.obstacleBodies) {
              chunk.obstacleBodies.forEach(b => {
                  const s = b.bounds.max.x - b.bounds.min.x;
                  ctx.save();
                  ctx.translate(b.position.x, b.position.y);
                  ctx.rotate(b.angle);
                  ctx.fillStyle = COLORS.obstacleBox;
                  ctx.fillRect(-s/2, -s/2, s, s);
                  ctx.strokeRect(-s/2, -s/2, s, s);
                  ctx.restore();
              });
          }
          if (chunk.boulderBodies) {
              chunk.boulderBodies.forEach(b => {
                  const r = (b.bounds.max.x - b.bounds.min.x)/2;
                  ctx.save();
                  ctx.translate(b.position.x, b.position.y);
                  ctx.rotate(b.angle);
                  ctx.fillStyle = COLORS.boulder;
                  ctx.beginPath(); ctx.arc(0,0,r,0,Math.PI*2); ctx.fill(); ctx.stroke();
                  ctx.restore();
              });
          }

          // Items
          chunk.coinBodies.forEach(b => {
              if(!collectedCoinIds.has(b.id)) {
                  ctx.translate(b.position.x, b.position.y);
                  ctx.fillStyle = COLORS.coinOuter;
                  ctx.beginPath(); ctx.arc(0,0, config.COIN_SIZE, 0, Math.PI*2); ctx.fill();
                  ctx.fillStyle = COLORS.coinInner;
                  ctx.beginPath(); ctx.arc(0,0, config.COIN_SIZE*0.7, 0, Math.PI*2); ctx.fill();
                  ctx.translate(-b.position.x, -b.position.y);
              }
          });
          chunk.fuelBodies.forEach(b => {
              if(!collectedFuelIds.has(b.id)) {
                  ctx.save();
                  ctx.translate(b.position.x, b.position.y);
                  ctx.fillStyle = COLORS.fuelCan;
                  ctx.fillRect(-10, -15, 20, 30);
                  ctx.fillStyle = '#facc15';
                  ctx.fillRect(0, -18, 8, 6);
                  ctx.restore();
              }
          });
      });

      // Draw Car
      const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
      const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');
      drawCar(ctx, chassis, wheelBack, wheelFront);

      // Particles
      particlesRef.current.forEach(p => {
          if (p.active) {
              ctx.fillStyle = p.type === 'explosion' ? '#ef4444' : (p.type === 'spark' ? '#fbbf24' : '#e5e7eb');
              ctx.globalAlpha = p.life / p.maxLife;
              ctx.beginPath(); ctx.arc(p.x, p.y, p.type === 'spark' ? 2 : 4, 0, Math.PI*2); ctx.fill();
              ctx.globalAlpha = 1.0;
          }
      });

      // FPS
      const now = performance.now();
      frameCountRef.current++;
      if (now - lastFpsTimeRef.current >= 500) {
          const fps = Math.round((frameCountRef.current * 1000) / (now - lastFpsTimeRef.current));
          if (hudFpsRef.current) hudFpsRef.current.innerText = `${fps} FPS`;
          lastFpsTimeRef.current = now;
          frameCountRef.current = 0;
      }

      requestRef.current = requestAnimationFrame(animate);
  }, [config, selectedCar, selectedMap, onGameOver, onLevelComplete, collectedCoinIds, collectedFuelIds, clouds, chunks, stars, isMenuBackground]);

  // Pause Handlers
  const togglePause = () => {
      if (isMenuBackground) return;
      setIsPaused(!isPaused); pausedRef.current = !pausedRef.current;
      if (soundManagerRef.current) pausedRef.current ? SoundManager.stopMusic() : soundManagerRef.current.resume();
  };
  const handleResume = () => { setIsPaused(false); pausedRef.current = false; soundManagerRef.current?.resume(); };
  const toggleMusic = () => soundManagerRef.current?.toggleMusic();

  // Input Listeners
  useEffect(() => {
    if (isMenuBackground) return;
    const kd = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
      if (e.key === 'Escape') togglePause();
    };
    const ku = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };
    window.addEventListener('keydown', kd); window.addEventListener('keyup', ku);
    return () => { window.removeEventListener('keydown', kd); window.removeEventListener('keyup', ku); };
  }, [isMenuBackground]);

  const gameClass = `relative w-full h-full bg-slate-900 overflow-hidden cursor-none select-none font-sans ${isMenuBackground ? 'grayscale opacity-60' : ''}`;

  return (
    <div ref={containerRef} className={gameClass}>

      {/* Top Bar */}
      {!isMenuBackground && (
      <div className="absolute top-4 right-4 z-30 flex gap-2 items-center">
         <div ref={hudFpsRef} className="mr-4 font-mono font-bold text-sm text-emerald-500 drop-shadow-md bg-black/40 backdrop-blur px-3 py-2 rounded-lg border border-white/10">60 FPS</div>
         <button onClick={toggleMusic} className="w-10 h-10 bg-black/40 backdrop-blur text-white rounded-full border border-white/20 flex items-center justify-center hover:bg-white/20 transition">🎵</button>
         <button onClick={togglePause} className="w-10 h-10 bg-black/40 backdrop-blur text-white rounded-full border border-white/20 flex items-center justify-center hover:bg-white/20 transition">⏸️</button>
         <button onClick={() => setIsDebugOpen(!isDebugOpen)} className="w-10 h-10 bg-black/40 backdrop-blur text-white rounded-full border border-white/20 flex items-center justify-center hover:bg-white/20 transition">⚙️</button>
      </div>
      )}

      {/* Pause Menu */}
      {isPaused && (
          <div className="absolute inset-0 z-40 bg-black/60 backdrop-blur-sm flex flex-col items-center justify-center animate-fade-in">
             <div className="bg-neutral-900 border border-neutral-700 p-8 rounded-2xl shadow-2xl flex flex-col gap-4 min-w-[300px]">
                 <h2 className="text-3xl font-black text-center text-white italic tracking-wider mb-2">PAUSED</h2>
                 <button onClick={handleResume} className="py-3 px-6 bg-amber-600 hover:bg-amber-500 rounded-xl font-bold text-white shadow-lg transition">RESUME</button>
                 <button onClick={onExit} className="py-3 px-6 bg-neutral-700 hover:bg-neutral-600 rounded-xl font-bold text-white shadow-lg transition">MAIN MENU</button>
             </div>
          </div>
      )}

      {/* HUD */}
      {!isMenuBackground && (
      <div className="absolute top-6 left-6 z-10 pointer-events-none flex flex-col gap-3">
         <div className="flex items-center gap-4">
            <div className="bg-black/60 backdrop-blur-md px-5 py-3 rounded-xl border border-white/10 shadow-lg min-w-[120px]">
                <div className="text-[10px] text-neutral-400 uppercase tracking-widest font-bold mb-1">Distance</div>
                <div className="flex items-baseline gap-1">
                    <span ref={hudDistanceRef} className="text-3xl font-mono font-bold text-white tracking-tighter">0</span>
                    <span className="text-sm text-neutral-500 font-bold">M</span>
                </div>
            </div>
            {mode === 'LEVELS' && levelConfig && (
                <div className="bg-black/60 backdrop-blur-md px-5 py-3 rounded-xl border border-blue-500/30 shadow-lg min-w-[120px]">
                    <div className="text-[10px] text-blue-400 uppercase tracking-widest font-bold mb-1">Target</div>
                     <div className="flex items-baseline gap-1">
                        <span className="text-3xl font-mono font-bold text-blue-100 tracking-tighter">{levelConfig.distance}</span>
                        <span className="text-sm text-blue-500 font-bold">M</span>
                    </div>
                </div>
            )}
             <div className="bg-black/60 backdrop-blur-md px-5 py-3 rounded-xl border border-amber-500/30 shadow-lg flex items-center gap-3">
                 <div className="w-8 h-8 rounded-full bg-amber-500 flex items-center justify-center text-black font-bold border-2 border-amber-300">$</div>
                 <div>
                    <div className="text-[10px] text-amber-500 uppercase tracking-widest font-bold">Credits</div>
                    <div ref={hudCoinsRef} className="text-2xl font-mono font-bold text-white tracking-tighter">0</div>
                 </div>
            </div>
        </div>
        <div className="w-64">
             <div className="flex justify-between items-end mb-1 px-1">
                <span className="text-[10px] text-white/50 uppercase font-bold tracking-widest">Fuel Level</span>
             </div>
             <div className="w-full h-2 bg-neutral-800 rounded-full overflow-hidden border border-white/5">
                <div ref={hudFuelBarRef} className="h-full bg-gradient-to-r from-red-500 to-amber-500 transition-all duration-200" style={{ width: '100%' }} />
             </div>
        </div>
      </div>
      )}

      {/* Notification */}
      {notification && (
          <div className="absolute top-32 left-1/2 transform -translate-x-1/2 z-40 animate-bounce flex flex-col items-center pointer-events-none">
              <div className="text-5xl font-black italic text-transparent bg-clip-text bg-gradient-to-b from-white to-neutral-400 drop-shadow-xl whitespace-nowrap">{notification.text}</div>
              {notification.subText && <div className="text-xl font-bold text-amber-400 drop-shadow-md mt-1 tracking-widest uppercase">{notification.subText}</div>}
          </div>
      )}

      {isDebugOpen && <DebugMenu config={config} onUpdate={onUpdateConfig} onClose={() => setIsDebugOpen(false)} onReset={onResetConfig} />}

      {/* Touch Controls */}
      {!isMenuBackground && (
      <>
      <div className="absolute bottom-10 left-10 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-2 border-white/10 bg-black/40 backdrop-blur-sm active:bg-white/10 active:border-red-500/50 transition-all transform active:scale-95 flex items-center justify-center group"
           onMouseDown={() => { gameStateRef.current.keys.left = true; soundManagerRef.current?.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; soundManagerRef.current?.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center opacity-70 group-hover:opacity-100">
               <span className="text-3xl text-red-400 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-400 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>
      <div className="absolute bottom-10 right-10 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-2 border-white/10 bg-black/40 backdrop-blur-sm active:bg-white/10 active:border-emerald-500/50 transition-all transform active:scale-95 flex items-center justify-center group"
           onMouseDown={() => { gameStateRef.current.keys.right = true; soundManagerRef.current?.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; soundManagerRef.current?.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center opacity-70 group-hover:opacity-100">
               <span className="text-3xl text-emerald-400 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>
      </>
      )}

      {/* Main Canvas with Resolution Control */}
      <canvas 
        ref={canvasRef}
        className="w-full h-full block"
        style={{
            imageRendering: config.PIXELATED ? 'pixelated' : 'auto'
        }}
      />

    </div>
  );
};

export default Game;

