export enum GameState {
  SPLASH = 'SPLASH',
  MENU = 'MENU',
  LOADING = 'LOADING',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  LEVEL_COMPLETE = 'LEVEL_COMPLETE',
  MAP_MAKER = 'MAP_MAKER',
  CAR_MAKER = 'CAR_MAKER',
}

export type GameMode = 'INFINITE' | 'LEVELS';

export interface LevelConfig {
  id: number;
  distance: number; // Target distance in meters
  name: string;
}

