                                    <line x1={-WHEEL_SIZE * 0.6} y1={WHEEL_SIZE * 0.35} x2={WHEEL_SIZE * 0.6} y2={-WHEEL_SIZE * 0.35} />
                                </g>
                             </g>

                             <g transform={`translate(${wheelOffset}, 20)`}>
                                <circle r={WHEEL_SIZE} fill="#171717" stroke="black" strokeWidth="1" />
                                <circle r={WHEEL_SIZE * 0.7} fill={car.wheelColor} />
                                <g stroke="#171717" strokeWidth="2">
                                    <line x1="0" y1={-WHEEL_SIZE * 0.7} x2="0" y2={WHEEL_SIZE * 0.7} />
                                    <line x1={-WHEEL_SIZE * 0.6} y1={-WHEEL_SIZE * 0.35} x2={WHEEL_SIZE * 0.6} y2={WHEEL_SIZE * 0.35} />
                                    <line x1={-WHEEL_SIZE * 0.6} y1={WHEEL_SIZE * 0.35} x2={WHEEL_SIZE * 0.6} y2={-WHEEL_SIZE * 0.35} />
                                </g>
                             </g>
                        </g>
                     </svg>
                  </div>

                  <div className="flex-1">
                    <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">{car.name}</h3>
                    <div className="flex items-center gap-2 mt-1 mb-4">
                        <span className="px-2 py-0.5 bg-neutral-700 text-neutral-300 text-[10px] font-bold uppercase rounded">{car.shape}</span>
                        <span className="px-2 py-0.5 bg-neutral-700 text-amber-500 text-[10px] font-bold uppercase rounded">{car.driveTrain}</span>
                    </div>

                    {/* Stats */}
                    <div className="space-y-1.5 text-[10px] font-mono tracking-wide text-neutral-400">
                      <StatBar label="MAX SPEED" value={car.speed} max={1.6} color="bg-blue-500" />
                      <StatBar label="ACCEL" value={car.acceleration} max={0.04} color="bg-amber-500" />
                      <StatBar label="HANDLING" value={car.friction} max={1.6} color="bg-emerald-500" />
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

const StatBar: React.FC<{ label: string; value: number; max: number; color: string; inverse?: boolean }> = ({ label, value, max, color, inverse }) => {
  let pct = (value / max) * 100;
  if (pct > 100) pct = 100;

  return (
    <div className="flex items-center gap-3">
      <div className="w-20 text-right font-bold opacity-60">{label}</div>
      <div className="flex-1 h-1.5 bg-neutral-800 rounded-full overflow-hidden">
        <div 
          className={`h-full rounded-full ${color}`} 
          style={{ width: `${pct}%` }}
        ></div>
      </div>
    </div>
  );
};

