import { GameConfig, CarModel, LevelConfig } from '../types';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // 0-2: Grass, 3: Lamp, 4: Fence, 5: Finish Line Flag
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  fuelBodies: any[];
  islandBodies: any[];
  rampBodies: any[];
  obstacleBodies: any[];
  boulderBodies: any[];
  finishLineBody?: any;
  endX: number; // Added endX property
  endY: number;
  endGlobalIndex: number;
  nextSegmentsSinceFuel: number; 
  id: number;
}

export const createEngine = (config: GameConfig) => {
  const engine = Matter.Engine.create();
  engine.gravity.y = config.GRAVITY;

  // High iterations for rigid constraints
  engine.positionIterations = 10;
  engine.velocityIterations = 10;

  return engine;
};

export const createCar = (x: number, y: number, carConfig: CarModel, gameConfig: GameConfig) => {
  // Use car specific config if available, fallback to global config
  const CAR_WIDTH = carConfig.width || gameConfig.CAR_WIDTH;
  const CAR_HEIGHT = carConfig.height || gameConfig.CAR_HEIGHT;
  const WHEEL_SIZE = carConfig.wheelSize || gameConfig.WHEEL_SIZE;

  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: carConfig.density, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: carConfig.bodyColor },
    chamfer: { radius: 15 } 
  });

  // Calculate offsets for vertical alignment
  // Positions the wheel anchor point near the edge of the chassis
  const wheelOffsetX = -CAR_WIDTH / 2 + WHEEL_SIZE;
  const wheelOffsetY = CAR_HEIGHT / 2;

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: carConfig.friction,       
    frictionStatic: 1.5, 
    density: 0.01,  // Reduced density to minimize wheel inertia/swing     
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  // Align wheels vertically with suspension points to prevent horizontal swing at rest
  const wheelA = Matter.Bodies.circle(x + wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x - wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  // Ultra-rigid settings to prevent side-to-side (pendulum) movement
  const suspensionStiffness = 1.0; 
  const suspensionDamping = 0.6;   
  const suspensionLength = 7; // Shortened slightly for tighter control

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: -wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

/**
 * Calculates the noise/height for a specific index. 
 * Supports different logic based on map type.
 */
export const getTerrainNoise = (globalIndex: number, config: GameConfig, mapType: string = 'earth'): number => {
    const baseHeight = 70;

    // Standard Logic
    const nx = globalIndex * config.TERRAIN_NOISE_FREQ_1;
    const nzOsc = Math.sin(nx * 0.2);
    let amp = 0.1;
    if (nzOsc > 0.3) amp = 1.0;
    else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

    const nPrimary = Math.sin(nx) * config.TERRAIN_AMP_1;
    const nSecondary = Math.cos(globalIndex * config.TERRAIN_NOISE_FREQ_2) * config.TERRAIN_AMP_2;
    const nRumble = Math.sin(globalIndex * config.TERRAIN_NOISE_FREQ_3) * config.TERRAIN_AMP_3;

    const difficultyMultiplier = Math.min(2.5, 1 + (globalIndex * 0.001));

    return (nPrimary + nSecondary + nRumble) * amp * difficultyMultiplier * baseHeight;
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number,
    isNight: boolean,
    config: GameConfig,
    mapType: string = 'earth',
    startSegmentsSinceFuel: number = 0,
    levelTargetDistance: number | null = null
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE, FUEL_CAN_SIZE, LAMP_SPACING } = config;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];
  const fuelBodies: any[] = [];
  const islandBodies: any[] = [];
  const rampBodies: any[] = [];
  const obstacleBodies: any[] = [];
  const boulderBodies: any[] = [];
  let finishLineBody = null;

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;
  let lastLampX = startX;
  let coinStreak = 0;
  let segmentsSinceFuel = startSegmentsSinceFuel;

  let finishLineGenerated = false;

  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;
    segmentsSinceFuel++;

    // Check if we passed level target
    if (levelTargetDistance !== null && currentX >= (200 + levelTargetDistance) && !finishLineGenerated) {
        // Flatten terrain for finish line
        const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);
        const noiseCurrent = noisePrev; // Flat
        const dy = -(noiseCurrent - noisePrev);
        currentY = prevY + dy;

        // Add finish line object
        finishLineGenerated = true;
        finishLineBody = Matter.Bodies.rectangle(currentX, currentY - 200, 20, 400, {
            isSensor: true,
            isStatic: true,
            label: 'finishLine',
            render: { visible: false }
        });

        // Add visual decoration for finish line
        decorations.push({
            x: currentX,
            y: currentY,
            angle: 0,
            scale: 1,
            type: 5 // Finish Line Type
        });
    } else {
        const noiseCurrent = getTerrainNoise(globalIndex, config, mapType);
        const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);
        const dy = -(noiseCurrent - noisePrev); 
        currentY = prevY + dy;
    }

    pathPoints.push({ x: currentX, y: currentY });

    // --- Analysis for features ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);
    const isFlatEnough = slopeFactor > 0.85; 
    let featurePlaced = false;

    // Skip obstacles near finish line
    if (finishLineGenerated) continue;

    // --- Decorations ---
    // 1. Grass (Earth Only)
    if (mapType === 'earth') {
        const density = 0.4 * slopeFactor; 
        if (Math.random() < density) {
            const t = Math.random();
            const decoX = prevX + (currentX - prevX) * t;
            const decoY = prevY + (currentY - prevY) * t;

            decorations.push({
                x: decoX,
                y: decoY,
                angle: angle,
                scale: 0.5 + Math.random() * 0.5,
                type: Math.floor(Math.random() * 3) 
            });
        }
    }

    // 2. Lamps
    const lampChance = isNight || mapType === 'highway';
    if (lampChance && (currentX - lastLampX) > LAMP_SPACING) {
        decorations.push({
            x: currentX,
            y: currentY,
            angle: angle,
            scale: 1.0,
            type: 3
        });
        lastLampX = currentX;
    }

    // 3. Fences (Highway)
    if (mapType === 'highway') {
        decorations.push({
            x: prevX,
            y: prevY,
            angle: angle,
            scale: 1.0,
            type: 4
        });
    }

    // --- Collectibles (Fuel & Coins) ---
    const forceFuel = segmentsSinceFuel >= 125; 
    const canSpawnFuel = (segmentsSinceFuel > 80 && isFlatEnough) || forceFuel;

    let fuelSpawnedHere = false;

    if (canSpawnFuel) {
        if (forceFuel || Math.random() < 0.1) {
             const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;

            const fuel = Matter.Bodies.rectangle(cx, cy, FUEL_CAN_SIZE * 0.8, FUEL_CAN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'fuel',
                angle: 0,
                render: { visible: false }
            });
            fuelBodies.push(fuel);
            segmentsSinceFuel = 0;
            coinStreak = 0; 
            fuelSpawnedHere = true;
        }
    }

    if (!fuelSpawnedHere && !featurePlaced) {
        let placeCoin = false;
        if (coinStreak > 0) {
            if (isFlatEnough) {
                placeCoin = true;
                coinStreak--;
            } else {
                coinStreak = 0;
            }
        } else {
            if (Math.random() < 0.05 && isFlatEnough) {
                coinStreak = 3 + Math.floor(Math.random() * 6);
                placeCoin = true;
                coinStreak--;
            }
        }

        if (placeCoin) {
            const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Ground
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: config.FRICTION || 1.0, 
         frictionStatic: config.FRICTION || 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  // Combine all bodies into composite
  const allBodies = [
      ...groundParts, 
      ...coinBodies, 
      ...fuelBodies, 
      ...islandBodies, 
      ...rampBodies, 
      ...obstacleBodies,
      ...boulderBodies,
      ...(finishLineBody ? [finishLineBody] : [])
  ];

  return { 
      composite: Matter.Composite.create({ bodies: allBodies }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      fuelBodies,
      islandBodies,
      rampBodies,
      obstacleBodies,
      boulderBodies,
      finishLineBody,
      endX: currentX, // Return the end X coordinate
      endY: currentY,
      endGlobalIndex: globalIndex,
      nextSegmentsSinceFuel: segmentsSinceFuel, 
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

import React, { useState, useEffect, useRef } from 'react';
import { GameConfig } from '../types';
import { getTerrainNoise } from '../utils/physics';

interface MapMakerProps {
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: number) => void;
  onClose: () => void;
}

const MapMaker: React.FC<MapMakerProps> = ({ config, onUpdateConfig, onClose }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [points, setPoints] = useState<{x: number, y: number}[]>([]);

  // Sliders to control
  const controls = [
    { label: 'Base Frequency', key: 'TERRAIN_NOISE_FREQ_1', min: 0.01, max: 0.5, step: 0.01 },
    { label: 'Base Amplitude', key: 'TERRAIN_AMP_1', min: 0.1, max: 3.0, step: 0.1 },
    { label: 'Detail Frequency', key: 'TERRAIN_NOISE_FREQ_2', min: 0.01, max: 1.0, step: 0.01 },
    { label: 'Detail Amplitude', key: 'TERRAIN_AMP_2', min: 0.0, max: 2.0, step: 0.1 },
    { label: 'Rumble Frequency', key: 'TERRAIN_NOISE_FREQ_3', min: 0.01, max: 2.0, step: 0.01 },
    { label: 'Rumble Amplitude', key: 'TERRAIN_AMP_3', min: 0.0, max: 0.5, step: 0.01 },
  ];

  // Generate Preview Points
  useEffect(() => {
    const pts = [];
    const segments = 100;
    const width = 800; // Visual width
    // Simulate about 100 game segments
    let lastY = 0;

    for (let i = 0; i < segments; i++) {
        // We use the same physics logic, but we need to accumulate y changes like the physics engine does
        const noiseCurrent = getTerrainNoise(i, config);
        const noisePrev = getTerrainNoise(i - 1, config);
        const dy = -(noiseCurrent - noisePrev);

        lastY += dy;
        // Scale x for canvas fitting
        pts.push({ x: i * (width/segments), y: lastY });
    }
    setPoints(pts);
  }, [config]);

  // Render Canvas
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw Grid
    ctx.strokeStyle = '#262626'; // neutral-800
    ctx.beginPath();
    for(let i=0; i<canvas.width; i+=40) { ctx.moveTo(i,0); ctx.lineTo(i, canvas.height); }
    for(let i=0; i<canvas.height; i+=40) { ctx.moveTo(0,i); ctx.lineTo(canvas.width, i); }
    ctx.stroke();

    // Center line
    const centerY = canvas.height / 2;
    ctx.strokeStyle = '#525252'; // neutral-600
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(0, centerY);
    ctx.lineTo(canvas.width, centerY);
    ctx.stroke();

    if (points.length < 2) return;

    // Draw Terrain
    ctx.strokeStyle = '#f59e0b'; // amber-500
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(points[0].x, centerY + points[0].y);

    for(let i=1; i<points.length; i++) {
        ctx.lineTo(points[i].x, centerY + points[i].y);
    }
    ctx.stroke();

    // Fill Ground
    ctx.lineTo(points[points.length-1].x, canvas.height);
    ctx.lineTo(points[0].x, canvas.height);
    ctx.fillStyle = 'rgba(245, 158, 11, 0.1)';
    ctx.fill();

  }, [points]);

  const handleCopy = () => {
    navigator.clipboard.writeText(JSON.stringify(config, null, 2));
    alert("Map Config copied!");
  };

  return (
    <div className="absolute inset-0 z-50 bg-neutral-900 text-white flex flex-col">
       <div className="p-6 border-b border-neutral-800 bg-neutral-900 flex justify-between items-center">
            <div>
                <h2 className="text-2xl font-black italic uppercase tracking-tighter">Map Editor</h2>
                <p className="text-xs text-neutral-500 uppercase tracking-widest">Terrain Laboratory</p>
            </div>
            <div className="flex gap-4">
                 <button onClick={handleCopy} className="px-4 py-2 bg-neutral-800 border border-neutral-700 rounded text-sm font-bold hover:bg-neutral-700 hover:text-white transition-colors">Copy Config</button>
                 <button onClick={onClose} className="px-4 py-2 bg-amber-600 rounded text-sm font-bold hover:bg-amber-500 transition-colors">Exit</button>
            </div>
       </div>

       <div className="flex-1 flex overflow-hidden">
            {/* Controls */}
            <div className="w-96 bg-neutral-900 p-6 overflow-y-auto border-r border-neutral-800 space-y-8">
                {controls.map((ctrl) => (
                    <div key={ctrl.key}>
                        <div className="flex justify-between text-xs font-bold uppercase tracking-wide mb-2 text-neutral-400">
                            <label>{ctrl.label}</label>
                            <span className="font-mono text-amber-500">{(config[ctrl.key as keyof GameConfig] as number).toFixed(3)}</span>
                        </div>
                        <input 
                            type="range"
                            min={ctrl.min}
                            max={ctrl.max}
                            step={ctrl.step}
                            value={config[ctrl.key as keyof GameConfig] as number}
                            onChange={(e) => onUpdateConfig(ctrl.key as keyof GameConfig, parseFloat(e.target.value))}
                            className="w-full h-1 bg-neutral-700 rounded-lg appearance-none cursor-pointer accent-amber-500 hover:accent-amber-400"
                        />
                    </div>
                ))}

                <div className="bg-neutral-800/50 p-4 rounded border border-neutral-700 text-xs text-neutral-500 leading-relaxed font-serif italic">
                    <p>Adjust the noise algorithms to shape the procedural terrain generation. Changes update the preview graph in real-time.</p>
                </div>
            </div>

            {/* Preview */}
            <div className="flex-1 p-10 flex items-center justify-center bg-black relative">
                 <div className="absolute top-6 left-6 text-neutral-600 font-mono text-xs uppercase tracking-widest">Terrain Preview // Slice 0-100</div>
                 <canvas 
                    ref={canvasRef} 
                    width={800} 
                    height={600} 
                    className="bg-neutral-900 border border-neutral-800 rounded-lg shadow-2xl"
                 />
            </div>
       </div>
    </div>
  );
};

export default MapMaker;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig, GameMode, LevelConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, TerrainChunk, Cloud } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

const Matter = (window as any).Matter;

interface GameProps {
  mode: GameMode;
  levelConfig?: LevelConfig;
  onGameOver: (distance: number, coins: number) => void;
  onLevelComplete: (coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: any) => void;
  onResetConfig: () => void;
  onExit: () => void;
  isMenuBackground?: boolean;
  onReady?: () => void;
}

interface Particle {
    x: number; y: number; vx: number; vy: number;
    life: number; maxLife: number; active: boolean;
    type: 'dust' | 'spark' | 'explosion';
}

const Game: React.FC<GameProps> = ({ mode, levelConfig, onGameOver, onLevelComplete, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig, onExit, isMenuBackground = false, onReady }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Game Logic Refs (Using refs for high-frequency loop to prevent stale closures and React overhead)
  const chunksRef = useRef<TerrainChunk[]>([]);
  const cloudsRef = useRef<Cloud[]>([]);
  const collectedCoinIdsRef = useRef<Set<number>>(new Set());
  const collectedFuelIdsRef = useRef<Set<number>>(new Set());
  const particlesRef = useRef<Particle[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 });

  const fuelRef = useRef(config.MAX_FUEL);
  const wheelGroundContacts = useRef(0);
  const isOutOfFuelRef = useRef(false);
  const gameStateRef = useRef({ distance: 0, coins: 0, isGameOver: false, keys: { left: false, right: false } });

  // Visual state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 });
  const [isPaused, setIsPaused] = useState(false);
  const pausedRef = useRef(false);
  const [isDebugOpen, setIsDebugOpen] = useState(false);
  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);
  const patternsRef = useRef<{[key: string]: CanvasPattern | null}>({});
  const carImageRef = useRef<HTMLImageElement | null>(null);
  const starsRef = useRef<{x: number, y: number, r: number, opacity: number}[]>([]);

  // FPS Logic
  const lastFpsTimeRef = useRef(0);
  const frameCountRef = useRef(0);
  const hudFpsRef = useRef<HTMLDivElement>(null);

  // HUD Refs
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const hudFuelBarRef = useRef<HTMLDivElement>(null);

  // Setup Stars
  useEffect(() => {
    if (selectedMap.backgroundType === 'moon') {
        const s = [];
        for(let i=0; i<150; i++) {
            s.push({ x: Math.random() * 2000, y: Math.random() * 1000 - 500, r: Math.random() * 2, opacity: Math.random() });
        }
        starsRef.current = s;
    } else {
        starsRef.current = [];
    }
  }, [selectedMap]);

  const addChunk = useCallback((startX: number) => {
    const { endY, globalIndex, segmentsSinceFuel } = lastChunkDataRef.current;
    const length = config.CHUNK_SIZE;
    const chunkId = Math.floor(startX / length);

    const newChunk = generateTerrainChunk(
        chunkId, startX, endY, globalIndex, length, false, config, selectedMap.backgroundType, segmentsSinceFuel,
        mode === 'LEVELS' && levelConfig ? levelConfig.distance : null
    );

    if (engineRef.current) Matter.World.add(engineRef.current.world, newChunk.composite);

    if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
        const newClouds = generateClouds(startX, length);
        cloudsRef.current = [...cloudsRef.current, ...newClouds];
    }

    lastChunkDataRef.current = {
        endX: startX + length,
        endY: newChunk.endY,
        globalIndex: newChunk.endGlobalIndex,
        segmentsSinceFuel: newChunk.nextSegmentsSinceFuel
    };

    chunksRef.current.push(newChunk);
  }, [config, selectedMap.backgroundType, mode, levelConfig]);

  const handleResize = useCallback(() => {
    if (canvasRef.current && containerRef.current) {
        const rw = containerRef.current.clientWidth * config.RESOLUTION;
        const rh = containerRef.current.clientHeight * config.RESOLUTION;
        canvasRef.current.width = rw;
        canvasRef.current.height = rh;
        patternsRef.current = {}; // Clear cache on resize
    }
  }, [config.RESOLUTION]);

  useEffect(() => {
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [handleResize]);

  useEffect(() => {
    if (!isMenuBackground) soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;
    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;
    Matter.World.add(engine.world, [car, createWall(-1000)]);

    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 }; 
    let currentGenX = 0;
    const buffer = isMenuBackground ? 4000 : config.INITIAL_BUFFER_DISTANCE;
    while (currentGenX < buffer) {
        addChunk(currentGenX);
        currentGenX += config.CHUNK_SIZE;
    }

    particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
        x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
    }));

    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const { bodyA, bodyB } = pair;
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';

            if ((isWheel(bodyA) && isGround(bodyB)) || (isWheel(bodyB) && isGround(bodyA))) {
                wheelGroundContacts.current++;
                const w = isWheel(bodyA) ? bodyA : bodyB;
                const speed = Matter.Vector.magnitude(w.velocity);
                if (speed > 5) spawnParticles(w.position.x, w.position.y + 15, 2, speed > 10 ? 'spark' : 'dust');
            }

            if ((bodyA.label === 'chassis' && bodyB.label === 'ground') || (bodyB.label === 'chassis' && bodyA.label === 'ground')) {
                if (isMenuBackground) return;
                const chassis = bodyA.label === 'chassis' ? bodyA : bodyB;
                if (Math.abs(chassis.angle) > Math.PI / 1.5) {
                    gameStateRef.current.isGameOver = true;
                    soundManagerRef.current?.stopContinuous();
                    onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                }
            }

            let item = null;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyA.label) && ['coin', 'fuel', 'finishLine'].includes(bodyB.label)) item = bodyB;
            if (['chassis', 'wheelBack', 'wheelFront'].includes(bodyB.label) && ['coin', 'fuel', 'finishLine'].includes(bodyA.label)) item = bodyA;

            if (item && !isMenuBackground) {
                if (item.label === 'finishLine') {
                    gameStateRef.current.isGameOver = true;
                    onLevelComplete(gameStateRef.current.coins);
                } else if (!collectedCoinIdsRef.current.has(item.id) && !collectedFuelIdsRef.current.has(item.id)) {
                    if (item.label === 'coin') {
                        collectedCoinIdsRef.current.add(item.id);
                        gameStateRef.current.coins += config.COIN_VALUE;
                        soundManagerRef.current?.playCoinSound();
                        Matter.World.remove(engine.world, item);
                    } else if (item.label === 'fuel') {
                        collectedFuelIdsRef.current.add(item.id);
                        fuelRef.current = Math.min(config.MAX_FUEL, fuelRef.current + config.FUEL_CAN_VALUE);
                        isOutOfFuelRef.current = false;
                        setNotification({ text: "FUEL!", id: Date.now() });
                        setTimeout(() => setNotification(null), 1500);
                        Matter.World.remove(engine.world, item);
                    }
                }
            }
        });
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        event.pairs.forEach((pair: any) => {
            const isWheel = (b: any) => b.label === 'wheelBack' || b.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'obstacle';
            if ((isWheel(pair.bodyA) && isGround(pair.bodyB)) || (isWheel(pair.bodyB) && isGround(pair.bodyA))) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        });
    });

    requestRef.current = requestAnimationFrame(animate);
    return () => {
        if (requestRef.current) cancelAnimationFrame(requestRef.current);
        Matter.Engine.clear(engine);
        if (soundManagerRef.current) soundManagerRef.current.stopContinuous();
    };
  }, [addChunk, selectedCar, onGameOver, onLevelComplete, config, isMenuBackground]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark' | 'explosion') => {
      let spawned = 0;
      for (let p of particlesRef.current) {
          if (spawned >= count) break;
          if (!p.active) {
              p.active = true; p.x = x; p.y = y; p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME; p.life = p.maxLife;
              p.vx = (Math.random() - 0.5) * 5; p.vy = (Math.random() - 0.5) * 5;
              spawned++;
          }
      }
  };

  const getPattern = (ctx: CanvasRenderingContext2D, type: string, color1: string, color2: string) => {
      const key = `${type}-${color1}-${color2}`;
      if (patternsRef.current[key]) return patternsRef.current[key];
      const pCanvas = document.createElement('canvas');
      const pCtx = pCanvas.getContext('2d')!;
      pCanvas.width = 40; pCanvas.height = 40;
      if (type === 'ground') {
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,40,40);
          pCtx.fillStyle = color2; pCtx.globalAlpha = 0.2;
          pCtx.beginPath(); pCtx.arc(10,10,2,0,Math.PI*2); pCtx.arc(30,30,3,0,Math.PI*2); pCtx.fill();
      } else if (type === 'striped') {
          pCanvas.width = 20; pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,40);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,40);
      } else if (type === 'checker') {
          pCanvas.width = 20; pCanvas.height = 20;
          pCtx.fillStyle = color1; pCtx.fillRect(0,0,20,20);
          pCtx.fillStyle = color2; pCtx.fillRect(0,0,10,10); pCtx.fillRect(10,10,10,10);
      }
      const pattern = ctx.createPattern(pCanvas, 'repeat');
      patternsRef.current[key] = pattern;
      return pattern;
  };

  const animate = useCallback(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d', { alpha: false });
    if (!canvas || !ctx || gameStateRef.current.isGameOver) {
        requestRef.current = requestAnimationFrame(animate);
        return;
    }

    if (!pausedRef.current) {
        Matter.Engine.update(engineRef.current, 1000 / 60);
        const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
        const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
        const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');

        // Physics Input
        const { keys } = gameStateRef.current;
        const speedRatio = Matter.Vector.magnitude(chassis.velocity) / 25;
        const isGrounded = wheelGroundContacts.current > 0;

        if (!isMenuBackground) {
            soundManagerRef.current?.updateContinuous(speedRatio, isGrounded, keys.right && !isOutOfFuelRef.current);
            if (keys.right && !isOutOfFuelRef.current) {
                fuelRef.current -= config.FUEL_CONSUMPTION;
                if (fuelRef.current <= 0) {
                    fuelRef.current = 0; isOutOfFuelRef.current = true;
                    setNotification({ text: "OUT OF FUEL", id: Date.now() });
                    setTimeout(() => { if (!gameStateRef.current.isGameOver) onGameOver(gameStateRef.current.distance, gameStateRef.current.coins); }, 3000);
                }
                const power = selectedCar.acceleration;
                if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.min(wheelB.angularVelocity + power, selectedCar.speed));
                if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.min(wheelF.angularVelocity + power, selectedCar.speed));
                if (chassis.angularVelocity > -config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            } else if (keys.left) {
                 if (selectedCar.driveTrain !== 'FWD') Matter.Body.setAngularVelocity(wheelB, Math.max(wheelB.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (selectedCar.driveTrain !== 'RWD') Matter.Body.setAngularVelocity(wheelF, Math.max(wheelF.angularVelocity - 0.1, -selectedCar.speed/2));
                 if (chassis.angularVelocity < config.MAX_ROTATION_SPEED) Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (isGrounded ? config.GROUND_ROTATION_SPEED : config.AIR_ROTATION_SPEED));
            }
        } else {
            // Menu background auto-driving
            Matter.Body.setAngularVelocity(wheelB, 0.5); Matter.Body.setAngularVelocity(wheelF, 0.5);
            if (chassis.position.y > 500) Matter.Body.setPosition(chassis, { x: 200, y: -100 });
        }

        // Camera & Chunking
        cameraPosRef.current = { x: chassis.position.x, y: chassis.position.y };
        if (chassis.position.x > lastChunkDataRef.current.endX - config.RENDER_DISTANCE) addChunk(lastChunkDataRef.current.endX);
        gameStateRef.current.distance = Math.max(0, Math.floor((chassis.position.x - 200) / 10));

        // HUD Updates
        if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${gameStateRef.current.distance}`;
        if (hudCoinsRef.current) hudCoinsRef.current.innerText = `${gameStateRef.current.coins}`;
        if (hudFuelBarRef.current) hudFuelBarRef.current.style.width = `${(fuelRef.current / config.MAX_FUEL) * 100}%`;
    }

    // --- RENDERING ---
    const zoom = cameraZoomRef.current;
    const vH = config.BASE_VIEWPORT_HEIGHT * zoom;
    const vW = (canvas.width / canvas.height) * vH; // UNIFORM SCALE: Adjust width to aspect ratio
    const scale = canvas.height / vH;

    const camX = cameraPosRef.current.x - vW * 0.3;
    const camY = cameraPosRef.current.y - vH * 0.6;

    ctx.setTransform(scale, 0, 0, scale, -camX * scale, -camY * scale);

    // Sky
    const skyGrad = ctx.createLinearGradient(camX, camY, camX, camY + vH);
    skyGrad.addColorStop(0, selectedMap.skyColorStart); skyGrad.addColorStop(1, selectedMap.skyColorEnd);
    ctx.fillStyle = skyGrad; ctx.fillRect(camX, camY, vW, vH);

    // Stars
    if (starsRef.current.length > 0) {
        ctx.fillStyle = 'white';
        starsRef.current.forEach(s => {
            const px = s.x + camX * 0.9;
            if (px > camX && px < camX + vW) {
                ctx.globalAlpha = s.opacity; ctx.beginPath(); ctx.arc(px, s.y, s.r, 0, Math.PI*2); ctx.fill();
            }
        });
        ctx.globalAlpha = 1;
    }

    // Clouds
    ctx.fillStyle = 'rgba(255,255,255,0.4)';
    cloudsRef.current.forEach(c => {
        if (c.x > camX - 300 && c.x < camX + vW + 300) {
            ctx.save(); ctx.translate(c.x, c.y); ctx.scale(c.scale, c.scale);
            ctx.beginPath(); ctx.arc(0,0,30,0,Math.PI*2); ctx.arc(35,10,35,0,Math.PI*2); ctx.arc(70,0,30,0,Math.PI*2); ctx.fill();
            ctx.restore();
        }
    });

    // Terrain
    const groundPat = getPattern(ctx, 'ground', selectedMap.groundColor, selectedMap.groundDarkColor);
    ctx.fillStyle = groundPat || selectedMap.groundColor;
    ctx.strokeStyle = selectedMap.groundDarkColor; ctx.lineWidth = 4;

    chunksRef.current.forEach(chunk => {
        if (chunk.endX < camX || chunk.pathData[0].x > camX + vW) return;
        ctx.beginPath(); ctx.moveTo(chunk.pathData[0].x, chunk.pathData[0].y);
        chunk.pathData.forEach(p => ctx.lineTo(p.x, p.y));
        ctx.lineTo(chunk.endX, chunk.endY + 1000); ctx.lineTo(chunk.pathData[0].x, chunk.pathData[0].y + 1000);
        ctx.fill(); ctx.stroke();

        chunk.decorations.forEach(d => {
            if (d.x < camX || d.x > camX + vW) return;
            ctx.save(); ctx.translate(d.x, d.y); ctx.rotate(d.angle); ctx.scale(d.scale, d.scale);
            if (d.type === 5) { // Finish
                ctx.fillStyle = 'white'; ctx.fillRect(0,-200,5,200); ctx.fillStyle = 'black'; ctx.beginPath(); ctx.moveTo(5,-200); ctx.lineTo(60,-175); ctx.lineTo(5,-150); ctx.fill();
            } else if (d.type === 3) { // Lamp
                ctx.fillStyle = '#444'; ctx.fillRect(-2,-80,4,80); ctx.fillStyle = '#ff0'; ctx.beginPath(); ctx.arc(10,-80,5,0,Math.PI*2); ctx.fill();
            } else if (selectedMap.backgroundType === 'earth') {
                 ctx.strokeStyle = COLORS.grassDetail; ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(0,-10); ctx.stroke();
            }
            ctx.restore();
        });

        chunk.coinBodies.forEach(b => {
            if (!collectedCoinIdsRef.current.has(b.id) && b.position.x > camX && b.position.x < camX + vW) {
                ctx.save(); ctx.translate(b.position.x, b.position.y);
                ctx.fillStyle = COLORS.coinOuter; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE,0,Math.PI*2); ctx.fill();
                ctx.fillStyle = COLORS.coinInner; ctx.beginPath(); ctx.arc(0,0,config.COIN_SIZE*0.7,0,Math.PI*2); ctx.fill();
                ctx.restore();
            }
        });
    });

    // Car
    const chassis = carRef.current.bodies.find((b: any) => b.label === 'chassis');
    const wheelB = carRef.current.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelF = carRef.current.bodies.find((b: any) => b.label === 'wheelFront');

    [wheelB, wheelF].forEach(w => {
        ctx.save(); ctx.translate(w.position.x, w.position.y); ctx.rotate(w.angle);
        const r = selectedCar.wheelSize || config.WHEEL_SIZE;
        ctx.fillStyle = '#222'; ctx.beginPath(); ctx.arc(0,0,r,0,Math.PI*2); ctx.fill();
        ctx.strokeStyle = '#000'; ctx.stroke();
        ctx.fillStyle = selectedCar.wheelColor; ctx.beginPath(); ctx.arc(0,0,r*0.6,0,Math.PI*2); ctx.fill();
        ctx.restore();
    });

    ctx.save(); ctx.translate(chassis.position.x, chassis.position.y); ctx.rotate(chassis.angle);
    let bodyFill: string | CanvasPattern = selectedCar.bodyColor;
    if (selectedCar.texture !== 'plain') bodyFill = getPattern(ctx, selectedCar.texture, selectedCar.bodyColor, selectedCar.textureColor2) || bodyFill;
    ctx.fillStyle = bodyFill;
    const cw = selectedCar.width || config.CAR_WIDTH; const ch = selectedCar.height || config.CAR_HEIGHT;
    ctx.fillRect(-cw/2, -ch/2, cw, ch); ctx.strokeRect(-cw/2, -ch/2, cw, ch);
    ctx.fillStyle = 'rgba(0,0,0,0.3)'; ctx.fillRect(cw*0.1, -ch*0.4, cw*0.3, ch*0.3);
    ctx.restore();

    // Particles
    particlesRef.current.forEach(p => {
        if (p.active) {
            ctx.fillStyle = p.type === 'spark' ? '#ff0' : '#ddd'; ctx.globalAlpha = p.life / p.maxLife;
            ctx.beginPath(); ctx.arc(p.x, p.y, 2, 0, Math.PI*2); ctx.fill();
            p.x += p.vx; p.y += p.vy; p.vy += 0.2; p.life--; if (p.life <= 0) p.active = false;
        }
    });
    ctx.globalAlpha = 1;

    // FPS
    const now = performance.now(); frameCountRef.current++;
    if (now - lastFpsTimeRef.current >= 500) {
        const fps = Math.round((frameCountRef.current * 1000) / (now - lastFpsTimeRef.current));
        if (hudFpsRef.current) hudFpsRef.current.innerText = `${fps} FPS`;
        lastFpsTimeRef.current = now; frameCountRef.current = 0;
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [config, selectedCar, selectedMap, onGameOver, onLevelComplete, isMenuBackground]);

  return (
    <div ref={containerRef} className={`relative w-full h-full bg-slate-900 overflow-hidden select-none ${isMenuBackground ? 'opacity-40 pointer-events-none' : ''}`}>
      {!isMenuBackground && (
          <>
            <div className="absolute top-4 right-4 z-30 flex gap-2">
                <div ref={hudFpsRef} className="font-mono text-xs text-emerald-500 bg-black/60 px-2 py-1 rounded">60 FPS</div>
                <button onClick={() => pausedRef.current = !pausedRef.current || setIsPaused(!isPaused)} className="w-8 h-8 bg-black/60 text-white rounded flex items-center justify-center">⏸</button>
            </div>
            <div className="absolute top-6 left-6 z-10 pointer-events-none flex flex-col gap-2">
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-white/10 flex flex-col">
                    <span className="text-[10px] text-neutral-400 uppercase font-bold">Distance</span>
                    <span ref={hudDistanceRef} className="text-2xl font-mono font-bold text-white">0</span>
                </div>
                <div className="bg-black/60 px-4 py-2 rounded-xl border border-amber-500/20 flex gap-3 items-center">
                    <div className="w-6 h-6 rounded-full bg-amber-500 text-black flex items-center justify-center text-xs font-bold">$</div>
                    <span ref={hudCoinsRef} className="text-xl font-mono font-bold text-white">0</span>
                </div>
                <div className="w-48 h-1.5 bg-neutral-800 rounded-full mt-2 overflow-hidden border border-white/5">
                    <div ref={hudFuelBarRef} className="h-full bg-red-500 transition-all duration-200" style={{ width: '100%' }} />
                </div>
            </div>
            {notification && (
                <div className="absolute top-1/3 left-1/2 -translate-x-1/2 z-40 text-4xl font-black italic text-white animate-bounce drop-shadow-lg">{notification.text}</div>
            )}
            <div className="absolute bottom-8 left-8 z-30 flex gap-4">
                 <button className="w-20 h-20 rounded-full bg-black/40 border border-white/20 text-white font-bold" onMouseDown={() => gameStateRef.current.keys.left = true} onMouseUp={() => gameStateRef.current.keys.left = false} onTouchStart={() => gameStateRef.current.keys.left = true} onTouchEnd={() => gameStateRef.current.keys.left = false}>L</button>
                 <button className="w-20 h-20 rounded-full bg-black/40 border border-white/20 text-white font-bold" onMouseDown={() => gameStateRef.current.keys.right = true} onMouseUp={() => gameStateRef.current.keys.right = false} onTouchStart={() => gameStateRef.current.keys.right = true} onTouchEnd={() => gameStateRef.current.keys.right = false}>R</button>
            </div>
          </>
      )}
      <canvas ref={canvasRef} className="w-full h-full" style={{ imageRendering: config.PIXELATED ? 'pixelated' : 'auto' }} />
    </div>
  );
};

export default Game;

