                                </pattern>
                              )}
                               {car.texture === 'checker' && (
                                <pattern id={patternId} patternUnits="userSpaceOnUse" width="10" height="10">
                                  <rect width="10" height="10" fill={car.bodyColor} /><rect width="5" height="5" fill={car.textureColor2} /><rect x="5" y="5" width="5" height="5" fill={car.textureColor2} />
                                </pattern>
                              )}
                               {car.texture === 'gradient' && (
                                <linearGradient id={patternId} x1="0" y1="0" x2="0" y2="1">
                                  <stop offset="0%" stopColor={car.textureColor2} /><stop offset="100%" stopColor={car.bodyColor} />
                                </linearGradient>
                              )}
                        </defs>
                        <rect x="-40" y="-10" width="80" height="20" fill={fillStyle} stroke="rgba(0,0,0,0.5)" />
                        <circle cx="-25" cy="12" r="8" fill="#111" /><circle cx="25" cy="12" r="8" fill="#111" />
